import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface BackupData {
  lastBackup: {
    time: string;
    size: string;
  };
  nextBackup: {
    scheduled: string;
    expectedSize: string;
  };
  recentBackups: { date: string; size: string }[];
}

export default function Widget() {
  const data = response.data as BackupData;
  const { lastBackup, nextBackup, recentBackups } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1C1C1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722', display: 'flex', alignItems: 'center' }}>
              Backup Status <Info sx={{ ml: 0.5, fontSize: 18 }} />
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107', mt: 1 }}>
              Last Backup: {new Date(lastBackup.time).toLocaleString()} ({lastBackup.size})
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107' }}>
              Next Scheduled: {new Date(nextBackup.scheduled).toLocaleString()} (Expected {nextBackup.expectedSize})
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#303030' }} />

          <Box>
            <Typography variant="body2" sx={{ mb: 1, color: '#FF5722' }}>
              Recent Backups
            </Typography>
            <Stack spacing={0.5}>
              {recentBackups.slice(0, 3).map((backup, index) => (
                <Box key={index} sx={{ display: 'flex', justifyContent: 'space-between', color: '#B0BEC5' }}>
                  <Typography variant="body2">{backup.date}</Typography>
                  <Typography variant="body2">{backup.size}</Typography>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
